// PASO 1. Leer el input y fijar defaults simples.
const input = $input.first().json.body || $input.first().json;
const question = String(input.question || '').trim();
const embeddedChunks = Array.isArray(input.embeddedChunks) ? input.embeddedChunks : [];
const patientContext = input.patientContext && typeof input.patientContext === 'object'
  ? input.patientContext
  : { age: 60, sex: 'masculino' };
const topK = Math.min(Math.max(Number(input.topK || 6), 1), 12);
const scope = ['all', 'prospectos', 'guias'].includes(input.scope) ? input.scope : 'all';
const startedAtMs = Date.now();

// PASO 2. Validar que haya pregunta y chunks.
if (!question || embeddedChunks.length === 0) {
  return [{
    json: {
      success: false,
      valid: false,
      error: 'Se requiere question y embeddedChunks[]'
    }
  }];
}

// PASO 3. Definir funciones declarativas para similitud.
function normalize(text) {
  const replacements = {
    panza: 'abdominal', barriga: 'abdominal', estomago: 'abdominal', pecho: 'toracico', torax: 'toracico',
    nausea: 'nauseas', vomitos: 'vomito', vomitar: 'vomito', gastrica: 'gastrointestinal', gastricas: 'gastrointestinal',
    anciano: 'adulto', geriatrico: 'adulto', remedio: 'medicamento', remedios: 'medicamentos'
  };

  const cleaned = String(text || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  return cleaned ? cleaned.split(' ').map((token) => replacements[token] || token) : [];
}

function buildVector(text, dims = 64) {
  const vector = Array(dims).fill(0);
  for (const token of normalize(text)) {
    let hash = 0;
    for (let i = 0; i < token.length; i++) hash = ((hash << 5) - hash) + token.charCodeAt(i);
    vector[Math.abs(hash) % dims] += 1;
  }
  const norm = Math.sqrt(vector.reduce((acc, value) => acc + (value * value), 0)) || 1;
  return vector.map((value) => Number((value / norm).toFixed(6)));
}

function cosine(a, b) {
  let sum = 0;
  for (let i = 0; i < Math.max(a.length, b.length); i++) sum += (a[i] || 0) * (b[i] || 0);
  return sum;
}

function lexicalOverlap(queryText, candidateText) {
  const queryTokens = new Set(normalize(queryText));
  const candidateTokens = new Set(normalize(candidateText));
  if (!queryTokens.size) return 0;
  let hits = 0;
  for (const token of queryTokens) if (candidateTokens.has(token)) hits += 1;
  return hits / queryTokens.size;
}

// PASO 4. Construir la consulta efectiva.
const patientBits = Object.entries(patientContext).map(([key, value]) => `${key}: ${value}`).join(', ');
const queryText = [question, patientBits].filter(Boolean).join(' | ');
const queryVector = buildVector(queryText);

// PASO 5. Filtrar por scope y rankear chunks.
const scopedChunks = embeddedChunks.filter((chunk) => {
  if (scope === 'prospectos') return chunk.category === 'prospecto';
  if (scope === 'guias') return chunk.category === 'guia';
  return true;
});

const scoredChunks = scopedChunks
  .map((chunk) => {
    const baseText = chunk.textForEmbedding || [chunk.title, chunk.section, ...(chunk.tags || []), chunk.text].join(' ');
    const semanticScore = cosine(queryVector, chunk.vector || buildVector(baseText));
    const lexicalScore = lexicalOverlap(queryText, baseText);
    const ageBoost = patientBits.includes('60') && /adultos? mayores?|geriatr/i.test(baseText) ? 0.04 : 0;
    const score = Number(((semanticScore * 0.72) + (lexicalScore * 0.24) + ageBoost).toFixed(4));
    return { ...chunk, semanticScore: Number(semanticScore.toFixed(4)), lexicalScore: Number(lexicalScore.toFixed(4)), score };
  })
  .filter((chunk) => chunk.score > 0.05)
  .sort((a, b) => b.score - a.score);

const retrievedChunks = scoredChunks.slice(0, topK);
const topScore = retrievedChunks[0] ? retrievedChunks[0].score : 0;
const evidenceSufficient = retrievedChunks.length > 0 && topScore >= 0.18;

return [{
  json: {
    success: true,
    valid: true,
    question,
    patientContext,
    topK,
    scope,
    startedAtMs,
    retrievedChunks,
    retrieval: {
      topK,
      returned: retrievedChunks.length,
      topScore: Number(topScore.toFixed(4)),
      minScoreThreshold: 0.18,
      scopeUsed: scope,
      availableChunks: scopedChunks.length
    },
    evidenceSufficient
  }
}];

// PASO 1. Leer retrieval y, si existe, la salida de la LLM.
const retrievalNode = $('⚙️ Caja negra - retrieval top-k').first().json;
const llmItems = $('🤖 OpenRouter').all();
const llmRaw = llmItems.length ? (llmItems[0].json?.choices?.[0]?.message?.content || '') : '';

// PASO 2. Intentar extraer JSON del texto del modelo.
function extractJson(text) {
  if (!text) return null;
  try { return JSON.parse(text); } catch (error) {}

  const cleaned = String(text).replace(/^```json/i, '').replace(/```$/i, '').trim();
  try { return JSON.parse(cleaned); } catch (error) {}

  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (error) {}
  }

  return null;
}

// PASO 3. Validar la salida contra las fuentes recuperadas.
const parsed = extractJson(llmRaw) || {};
const retrievedChunks = retrievalNode.retrievedChunks || [];
const sourceMap = new Map(retrievedChunks.map((chunk) => [chunk.chunkId, chunk]));
const errors = [];

if (!retrievalNode.evidenceSufficient) errors.push('insufficient-evidence');
if (retrievalNode.evidenceSufficient) {
  if (!parsed.answer || typeof parsed.answer !== 'string' || !parsed.answer.trim()) errors.push('missing-answer');
  if (!Array.isArray(parsed.sources) || parsed.sources.length === 0) errors.push('missing-sources');
}

const groundedSources = Array.isArray(parsed.sources)
  ? parsed.sources
      .map((source) => sourceMap.get(source.chunkId))
      .filter(Boolean)
      .map((chunk) => ({
        chunkId: chunk.chunkId,
        docId: chunk.docId,
        title: chunk.title,
        section: chunk.section,
        score: chunk.score,
        evidence: String(chunk.text || '').slice(0, 180)
      }))
  : [];

if (retrievalNode.evidenceSufficient && groundedSources.length === 0) errors.push('sources-not-grounded');

// PASO 4. Si algo falla, devolver fallback seguro.
const fallbackUsed = errors.length > 0;

return [{
  json: {
    success: true,
    question: retrievalNode.question,
    patientContext: retrievalNode.patientContext,
    answer: fallbackUsed
      ? 'No se pudo validar una respuesta trazable del modelo. Dejo los fragmentos con mejor score para revision humana. Este sistema no reemplaza evaluacion profesional.'
      : parsed.answer.trim(),
    sources: fallbackUsed
      ? retrievedChunks.slice(0, 3).map((chunk) => ({
          chunkId: chunk.chunkId,
          docId: chunk.docId,
          title: chunk.title,
          section: chunk.section,
          score: chunk.score,
          evidence: String(chunk.text || '').slice(0, 180)
        }))
      : groundedSources.slice(0, 3),
    confidence: fallbackUsed ? 'baja' : (['alta', 'media', 'baja'].includes(parsed.confidence) ? parsed.confidence : 'media'),
    fallbackUsed,
    fallbackReason: fallbackUsed ? errors[0] : null,
    requiresHumanReview: true,
    retrieval: retrievalNode.retrieval,
    log: {
      event: 'rag_consulta_documental',
      ts: new Date().toISOString(),
      latencyMs: Math.max(Date.now() - (retrievalNode.startedAtMs || Date.now()), 0),
      returnedChunks: retrievalNode.retrieval ? retrievalNode.retrieval.returned : 0,
      topScore: retrievalNode.retrieval ? retrievalNode.retrieval.topScore : 0,
      fallbackUsed,
      fallbackReason: fallbackUsed ? errors[0] : null,
      sourceType: fallbackUsed ? 'guardrail-fallback' : 'draft-validated'
    }
  }
}];
